// test/utils.tsx — custom render dùng cho toàn dự án
import { render, RenderOptions } from '@testing-library/react';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { AuthProvider } from '@/context/AuthContext';

interface CustomRenderOptions extends RenderOptions {
  initialUser?: { name: string; role: string };
}

export function renderWithProviders(
  ui: React.ReactElement,
  { initialUser = { name: 'Test User', role: 'user' }, ...options }: CustomRenderOptions = {}
) {
  const queryClient = new QueryClient({
    defaultOptions: { queries: { retry: false } }, // không retry trong test
  });

  function Wrapper({ children }: { children: React.ReactNode }) {
    return (
      <QueryClientProvider client={queryClient}>
        <AuthProvider initialUser={initialUser}>
          {children}
        </AuthProvider>
      </QueryClientProvider>
    );
  }

  return render(ui, { wrapper: Wrapper, ...options });
}

// Dùng trong test
test('admin thấy nút xóa', () => {
  renderWithProviders(<UserCard userId="1" />, {
    initialUser: { name: 'Admin', role: 'admin' },
  });
  expect(screen.getByRole('button', { name: /xóa/i })).toBeInTheDocument();
});

