import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { server } from '../mocks/server';
import { http, HttpResponse } from 'msw';

// Helper: fresh QueryClient không retry
function createTestQueryClient() {
  return new QueryClient({
    defaultOptions: {
      queries: { retry: false, gcTime: 0 },
    },
  });
}

function renderWithQuery(ui: React.ReactElement) {
  const queryClient = createTestQueryClient();
  return render(
    <QueryClientProvider client={queryClient}>{ui}</QueryClientProvider>
  );
}

// Test success state
test('hiển thị danh sách sản phẩm', async () => {
  // MSW đã setup: GET /api/products trả về 2 sản phẩm
  renderWithQuery(<ProductList />);

  // Loading state
  expect(screen.getByText(/đang tải/i)).toBeInTheDocument();

  // Success state sau khi fetch xong
  expect(await screen.findByText('Áo thun')).toBeInTheDocument();
  expect(screen.getByText('Quần jean')).toBeInTheDocument();
});

// Test error state
test('hiển thị lỗi khi API fail', async () => {
  server.use(
    http.get('/api/products', () =>
      HttpResponse.json({ message: 'Server Error' }, { status: 500 })
    )
  );
  renderWithQuery(<ProductList />);
  expect(await screen.findByText(/lỗi kết nối/i)).toBeInTheDocument();
});

