import { renderHook, act } from '@testing-library/react';
import { useCounter } from '@/hooks/useCounter';
import { useDebounce } from '@/hooks/useDebounce';

// Test hook đơn giản
test('useCounter tăng/giảm đúng', () => {
  const { result } = renderHook(() => useCounter(0));

  expect(result.current.count).toBe(0);

  act(() => result.current.increment());
  expect(result.current.count).toBe(1);

  act(() => result.current.decrement());
  expect(result.current.count).toBe(0);
});

// Test hook nhận arguments
test('useCounter bắt đầu từ initialValue', () => {
  const { result } = renderHook((props) => useCounter(props.initial), {
    initialProps: { initial: 10 },
  });
  expect(result.current.count).toBe(10);
});

// Test async hook (fetch data)
test('useUserData fetch và trả về user', async () => {
  // MSW đã setup handler cho /api/users/1
  const { result } = renderHook(() => useUserData('1'));

  expect(result.current.isLoading).toBe(true);

  // Chờ async operation hoàn thành
  await waitFor(() => expect(result.current.isLoading).toBe(false));

  expect(result.current.data?.name).toBe('Nguyễn Văn An');
});

