// ── TYPICAL TEST FILE ─────────────────────────────────────
import { renderWithProviders } from '@/test/utils'; // custom render
import userEvent from '@testing-library/user-event';
import { server } from '@/test/mocks/server';
import { http, HttpResponse } from 'msw';

describe('CheckoutPage', () => {
  const user = userEvent.setup();

  it('hiển thị form thanh toán', () => {
    renderWithProviders(<CheckoutPage />);
    expect(screen.getByLabelText('Số thẻ')).toBeInTheDocument();
  });

  it('thanh toán thành công', async () => {
    renderWithProviders(<CheckoutPage />);
    await user.type(screen.getByLabelText('Số thẻ'), '4111111111111111');
    await user.click(screen.getByRole('button', { name: /thanh toán/i }));
    expect(await screen.findByText('Thanh toán thành công!')).toBeVisible();
  });

  it('hiển thị lỗi khi card bị từ chối', async () => {
    server.use(
      http.post('/api/checkout', () =>
        HttpResponse.json({ error: 'Card bị từ chối' }, { status: 402 })
      )
    );
    renderWithProviders(<CheckoutPage />);
    await user.click(screen.getByRole('button', { name: /thanh toán/i }));
    expect(await screen.findByRole('alert')).toHaveTextContent('Card bị từ chối');
  });
});
